    function withTimeout(promise, ms, label) {
      return Promise.race([
        promise,
        new Promise((_, reject) => setTimeout(() => reject(new Error(`${label} tardó demasiado. Revisa conexión, URL del proyecto, publishable key y estado de Supabase.`)), ms))
      ]);
    }

