    function showToast(message,type='success'){const c=$('toast-container');const t=document.createElement('div');t.className=`${type==='success'?'bg-instVerdeClaro':'bg-instTomate'} text-white px-6 py-3 rounded-xl shadow-lg flex items-center gap-3 transform transition-all duration-300 translate-x-full opacity-0 pointer-events-auto`;t.innerHTML=`<i class="fa-solid ${type==='success'?'fa-check-circle':'fa-circle-exclamation'} text-xl"></i><span class="font-medium text-sm">${esc(message)}</span>`;c.appendChild(t);setTimeout(()=>t.classList.remove('translate-x-full','opacity-0'),10);setTimeout(()=>{t.classList.add('translate-x-full','opacity-0');setTimeout(()=>t.remove(),300)},3200)}

    function getParamRobust(param){const url=window.location.href;const regex=new RegExp('[?&#]'+param+'=([^&#]*)','i');const match=regex.exec(url);return match?decodeURIComponent(match[1]).trim():null}
    function isRatingRoute(){return !!getParamRobust('rate_ticket')}
    function closeRatingScreen(message='Gracias. Esta ventana ya puede cerrarse.'){ $('rating-form').classList.add('hidden'); $('rating-ticket-box').classList.add('hidden'); $('rating-error-message').classList.add('hidden'); $('rating-success-message').classList.remove('hidden'); $('rating-success-message').innerHTML=`<i class="fa-solid fa-circle-check text-5xl text-instVerdeClaro mb-4"></i><h3 class="text-xl font-bold text-gray-800">${esc(message)}</h3><p class="text-gray-600 mt-2">Puedes cerrar esta pestaña.</p>`; setTimeout(()=>{try{window.close()}catch(e){}},1600); }

    async function initRatingView(){ $('loading-screen').classList.remove('hidden'); $('app-container').classList.add('hidden'); $('auth-overlay').classList.add('hidden'); const ticketId=getParamRobust('rate_ticket'); const token=getParamRobust('token'); if(!ticketId||!token){$('loading-screen').classList.add('hidden');$('public-rating-view').classList.remove('hidden');$('public-rating-view').classList.add('flex');$('rating-error-message').classList.remove('hidden');$('rating-error-message').textContent='El enlace de valoración no es válido.';$('rating-form').classList.add('hidden');return}
      const {data:t,error}=await sbClient.from('tickets').select('id,id_str,asunto,estado,usuario_nombre,valoracion_calificacion,rating_token').eq('id',ticketId).eq('rating_token',token).maybeSingle(); $('loading-screen').classList.add('hidden'); $('public-rating-view').classList.remove('hidden'); $('public-rating-view').classList.add('flex'); if(error||!t){$('rating-error-message').classList.remove('hidden');$('rating-error-message').textContent='Ticket no encontrado o enlace vencido.';$('rating-form').classList.add('hidden');return} if(t.valoracion_calificacion){closeRatingScreen('Este ticket ya fue valorado.');return} if(t.estado!=='Resuelto'){ $('rating-error-message').classList.remove('hidden');$('rating-error-message').textContent='Este ticket aún no está marcado como resuelto.';$('rating-form').classList.add('hidden');return }
      $('rating-ticket-id').textContent=t.id_str||t.id; $('rating-user-name').textContent=t.usuario_nombre||'Usuario'; $('rating-ticket-subject').textContent=t.asunto||'el incidente'; const stars=document.querySelectorAll('.star-rating i'); const texts=['Malo','Regular','Bueno','Muy Bueno','Excelente']; stars.forEach(star=>{star.onclick=e=>{const val=Number(e.target.dataset.value);$('rating-value').value=val;$('rating-text').textContent=texts[val-1];stars.forEach((s,i)=>s.classList.toggle('active',i<val));}}); $('rating-form').onsubmit=async e=>{e.preventDefault(); const rating=Number($('rating-value').value); if(!rating){showToast('Selecciona una calificación','error');return} $('btn-submit-rating').disabled=true; $('btn-submit-rating').innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Guardando...'; const {error:upErr}=await sbClient.from('tickets').update({valoracion_calificacion:rating,valoracion_comentario:$('rating-comment').value,valoracion_fecha:new Date().toISOString(),rating_token:null}).eq('id',ticketId).eq('rating_token',token).is('valoracion_calificacion',null); if(upErr){$('rating-error-message').classList.remove('hidden');$('rating-error-message').textContent=upErr.message;$('btn-submit-rating').disabled=false;$('btn-submit-rating').textContent='Intentar nuevamente'} else closeRatingScreen('¡Gracias por tu opinión!') };
    }

    async function initApp(){
      try {
        if(isRatingRoute()){ await initRatingView(); return }
        const {data:{session}} = await withTimeout(sbClient.auth.getSession(), 15000, 'Validación de sesión');
        if(session){
          currentUser=session.user;
          await loadProfile();
          await loadAll();
          showApp();
        } else {
          showAuth();
        }
        $('loading-screen').classList.add('hidden');
      } catch(error) {
        console.error('Error initApp:', error);
        showBootError('La aplicación no pudo validar la sesión o cargar los datos iniciales.', error?.message || error);
      }
    }
    function showAuth(){ $('auth-overlay').classList.remove('hidden'); $('auth-overlay').classList.add('flex'); $('app-container').classList.add('hidden'); initAuthFromUrl(); }
    function showApp(){
      $('auth-overlay').classList.add('hidden'); $('auth-overlay').classList.remove('flex'); $('app-container').classList.remove('hidden');
      $('display-agent-name').textContent=currentProfile?.nombre_completo||currentUser.email; $('display-agent-role').textContent=currentProfile?.rol||'agent';
      const admin = isAdmin();
      if($('agents-admin-panel')) $('agents-admin-panel').classList.toggle('hidden', !admin);
      if($('agents-not-admin')) $('agents-not-admin').classList.toggle('hidden', admin);
    }
    async function loadProfile(){
      const {data,error}=await withTimeout(sbClient.from('agentes').select('*').eq('auth_user_id',currentUser.id).maybeSingle(), 15000, 'Consulta de perfil de agente');
      if(error) throw new Error(`No se pudo consultar la tabla agentes: ${error.message}`);
      if(!data){
        const name=currentUser.user_metadata?.full_name||currentUser.email;
        const invitedRole = currentUser.user_metadata?.role || getParamRobust('role') || 'agent';
        const {data:newP,error:insertError}=await sbClient.from('agentes').insert({auth_user_id:currentUser.id,nombre_completo:name,email:currentUser.email,rol:invitedRole === 'admin' ? 'admin' : 'agent'}).select().single();
        if(insertError) throw new Error(`No se pudo crear el perfil del agente: ${insertError.message}`);
        currentProfile=newP;
      } else currentProfile=data;
    }
    async function safeLoad(label, fn){
      try { await withTimeout(fn(), 20000, label); }
      catch(e){ console.error(label, e); showToast(`${label}: ${e.message || e}`,'error'); }
    }
    async function loadAll(){
      await safeLoad('Configuración', loadConfig);
      await safeLoad('Directorio', loadDirectory);
      await safeLoad('Tickets', loadTickets);
      await safeLoad('Agentes', loadAgents);
      try { actualizarSelectsConfig(); renderDirectorio(); renderTickets(); renderAgents(); populateDashboardFilters(); renderDashboard(); populateInformeFilters(); renderInformePreview(); }
      catch(e){ console.error('Render inicial', e); showToast(`Vista inicial: ${e.message}`,'error'); }
      subscribeRealtime();
    }
    let subscribed=false; function subscribeRealtime(){
      if(subscribed)return; subscribed=true;
      try{
        sbClient.channel('public-changes')
          .on('postgres_changes',{event:'*',schema:'public',table:'tickets'},()=>loadTickets().then(()=>{renderTickets();populateDashboardFilters();renderDashboard();populateInformeFilters();renderInformePreview();}).catch(console.error))
          .on('postgres_changes',{event:'*',schema:'public',table:'directorio'},()=>loadDirectory().then(()=>renderDirectorio()).catch(console.error))
          .on('postgres_changes',{event:'*',schema:'public',table:'app_config'},()=>loadConfig().then(()=>{actualizarSelectsConfig();populateDashboardFilters();populateInformeFilters();}).catch(console.error))
          .on('postgres_changes',{event:'*',schema:'public',table:'agentes'},()=>loadAgents().then(()=>renderAgents()).catch(console.error))
          .subscribe();
      } catch(e){ console.warn('Realtime no disponible:', e); }
    }
    async function loadConfig(){ const {data,error}=await sbClient.from('app_config').select('*').eq('id',1).maybeSingle(); if(error) throw new Error(error.message); configData=data?.config||defaultConfig; }
    async function loadDirectory(){ const {data,error}=await sbClient.from('directorio').select('*').order('nombres'); if(error) throw new Error(error.message); directorioData=data||[]; }
    async function loadTickets(){ const {data,error}=await sbClient.from('tickets').select('*').order('created_at',{ascending:false}); if(error) throw new Error(error.message); ticketsData=data||[]; }
    async function loadAgents(){ const {data,error}=await sbClient.from('agentes').select('*').order('created_at',{ascending:false}); if(error) throw new Error(error.message); agentsData=data||[]; }

    function setAuthMode(mode){
      ['login','register','reset'].forEach(m=>$(m+'-form').classList.toggle('hidden',m!==mode));
      $('show-login').classList.toggle('hidden',mode==='login'); $('show-register').classList.toggle('hidden',mode==='register'); $('show-reset').classList.toggle('hidden',mode==='reset');
      $('auth-title').textContent=mode==='login'?'Ingreso de Agentes':mode==='register'?'Registro de Agente':'Recuperar contraseña';
      $('auth-subtitle').textContent=mode==='login'?'Accede con tu correo y contraseña institucional.':mode==='register'?'Crea tu usuario para operar el sistema.':'Recibirás un enlace de recuperación en tu correo.';
      applyAuthPrefill();
    }
    function applyAuthPrefill(){
      const email=getParamRobust('email'), name=getParamRobust('name'), role=getParamRobust('role');
      if(email){ if($('login-email')) $('login-email').value=email; if($('reg-email')) $('reg-email').value=email; if($('reset-email')) $('reset-email').value=email; }
      if(name && $('reg-name')) $('reg-name').value=name;
      if(role && $('reg-role')) { $('reg-role').value = role === 'admin' ? 'admin' : 'agent'; $('reg-role-label').textContent = role === 'admin' ? 'Administrador' : 'Agente'; $('reg-role-display').classList.remove('hidden'); }
    }
    function initAuthFromUrl(){
      applyAuthPrefill();
      const mode=(getParamRobust('auth')||'login').toLowerCase();
      if(['login','register','reset'].includes(mode)) setAuthMode(mode);
    }
    $('show-login').onclick=()=>setAuthMode('login'); $('show-register').onclick=()=>setAuthMode('register'); $('show-reset').onclick=()=>setAuthMode('reset');
    $('login-form').onsubmit=async e=>{e.preventDefault(); const {data,error}=await sbClient.auth.signInWithPassword({email:$('login-email').value,password:$('login-password').value}); if(error)return showToast(error.message,'error'); currentUser=data.user; await loadProfile(); await loadAll(); showApp(); showToast('Bienvenido')};
    $('register-form').onsubmit=async e=>{e.preventDefault(); const name=$('reg-name').value.trim(), email=$('reg-email').value.trim(), password=$('reg-password').value; const {data,error}=await sbClient.auth.signUp({email,password,options:{data:{full_name:name,role:$('reg-role').value},emailRedirectTo:window.location.origin+window.location.pathname}}); if(error)return showToast(error.message,'error'); if(data.user){await sbClient.from('agentes').upsert({auth_user_id:data.user.id,nombre_completo:name,email,rol:$('reg-role').value,activo:true},{onConflict:'auth_user_id'});} showToast('Cuenta creada. Si Supabase solicita confirmación, revisa el correo.'); setAuthMode('login')};
    $('reset-form').onsubmit=async e=>{e.preventDefault(); const {error}=await sbClient.auth.resetPasswordForEmail($('reset-email').value,{redirectTo:window.location.origin+window.location.pathname}); if(error)return showToast(error.message,'error'); showToast('Enlace de recuperación enviado')};
    async function logout(){ await sbClient.auth.signOut(); location.reload(); }
    window.logout=logout;

    function switchTab(tabId){ document.querySelectorAll('.tab-content').forEach(t=>t.classList.remove('active')); $(tabId).classList.add('active'); document.querySelectorAll('.nav-btn').forEach(b=>{b.classList.remove('bg-instVerdeClaro','text-instVerdeOscuro','shadow-md');b.classList.add('hover:bg-white/10','text-white')}); const btn=$('btn-'+tabId); if(btn){btn.classList.remove('hover:bg-white/10','text-white');btn.classList.add('bg-instVerdeClaro','text-instVerdeOscuro','shadow-md')} if(tabId==='tab-dashboard'){populateDashboardFilters();renderDashboard()} if(tabId==='tab-informe'){populateInformeFilters();renderInformePreview()} }
    window.switchTab=switchTab; window.toggleMobileMenu=()=>{const s=document.querySelector('aside');s.classList.toggle('hidden');s.classList.toggle('absolute');s.classList.toggle('h-full');s.classList.toggle('z-50')};

    $('search-user').addEventListener('input',e=>{ const term=e.target.value.toLowerCase(); const box=$('search-results'); if(term.length<2){box.classList.add('hidden');return} const matches=directorioData.filter(u=>(u.nombres||'').toLowerCase().includes(term)||(u.cedula||'').includes(term)).slice(0,8); box.innerHTML=matches.length?matches.map(u=>`<li data-id="${u.id}" class="p-3 hover:bg-gray-50 cursor-pointer border-b text-sm"><div class="font-semibold text-instVerdeOscuro">${esc(u.nombres)}</div><div class="text-xs text-gray-500">C.I: ${esc(u.cedula)} | ${esc(u.tipo)}</div></li>`).join(''):'<li class="p-3 text-sm text-gray-500 text-center">No encontrado</li>'; box.querySelectorAll('li[data-id]').forEach(li=>li.onclick=()=>seleccionarUsuario(directorioData.find(u=>u.id===li.dataset.id))); box.classList.remove('hidden'); });
    document.addEventListener('click',e=>{ if(!e.target.closest('#search-results')&&!e.target.closest('#search-user')) $('search-results').classList.add('hidden') });
    function seleccionarUsuario(u){ if(!u)return; $('u-id').value=u.id; $('u-nombre').value=u.nombres||''; $('u-cedula').value=u.cedula||''; $('u-tipo').value=u.tipo||''; $('u-periodo').value=u.periodo||''; $('u-correo').value=u.correo||''; $('search-user').value=''; $('search-results').classList.add('hidden'); }

    async function guardarTicket(estado){ const form=$('ticket-form'); if(!form.checkValidity()||!$('u-cedula').value){showToast('Completa campos y selecciona usuario','error');return} const ticket={id_str:'TKT-'+Math.floor(Math.random()*100000).toString().padStart(5,'0'),fecha_texto:new Date().toLocaleString(),agente_id:currentProfile?.id||null,agente_nombre:currentProfile?.nombre_completo||currentUser.email,usuario_id:$('u-id').value||null,usuario_cedula:$('u-cedula').value,usuario_nombre:$('u-nombre').value,asunto:$('t-asunto').value,categoria:$('t-categoria').value,subcategoria:$('t-subcategoria').value,prioridad:$('t-prioridad').value,canal:$('t-canal').value,descripcion:$('t-descripcion').value,estado,rating_token:estado==='Resuelto'?randomToken():null}; const {error}=await sbClient.from('tickets').insert(ticket); if(error)return showToast(error.message,'error'); form.reset(); ['u-id','u-nombre','u-cedula','u-tipo','u-periodo','u-correo'].forEach(id=>$(id).value=''); showToast('Ticket guardado'); await loadTickets(); renderTickets(); }
    window.guardarTicket=guardarTicket;

    function renderTickets(){ const tbody=$('tickets-table-body'); const ft=($('filter-tickets')?.value||'').toLowerCase(); const filtered=ticketsData.filter(t=>!ft||[t.id_str,t.usuario_nombre,t.asunto,t.categoria,t.estado,t.agente_nombre].some(v=>String(v||'').toLowerCase().includes(ft))); $('empty-tickets').classList.toggle('hidden',filtered.length!==0); tbody.innerHTML=filtered.map(t=>{const badge=t.estado==='Resuelto'?'bg-green-100 text-green-700 border-green-200':'bg-orange-100 text-orange-700 border-orange-200'; const rating=t.valoracion_calificacion?`<div>${[1,2,3,4,5].map(i=>`<i class="fa-solid fa-star ${i<=t.valoracion_calificacion?'text-yellow-400':'text-gray-200'}"></i>`).join('')}</div>`:'<span class="text-xs text-gray-400 italic">Pendiente</span>'; return `<tr class="hover:bg-gray-50"><td class="px-6 py-4"><div class="font-bold text-instVerdeOscuro">${esc(t.id_str)}</div><div class="text-xs text-gray-500">${esc((t.created_at||'').slice(0,10))}</div></td><td class="px-6 py-4"><div class="font-medium">${esc(t.usuario_nombre)}</div><div class="text-xs text-gray-500"><i class="fa-solid fa-headset mr-1"></i>${esc(t.agente_nombre)}</div></td><td class="px-6 py-4 truncate max-w-xs" title="${esc(t.asunto)}"><div class="font-medium">${esc(t.asunto)}</div><div class="text-xs text-instPlomo">${esc(t.categoria)}</div></td><td class="px-6 py-4"><span class="px-3 py-1 rounded-full text-xs font-semibold border ${badge}">${esc(t.estado)}</span></td><td class="px-6 py-4 text-center">${rating}</td><td class="px-6 py-4 text-center">${t.estado==='Resuelto'?`<button onclick="abrirModalLink('${t.id}')" class="text-yellow-500 hover:bg-yellow-50 p-2 rounded mr-1" title="Solicitar valoración"><i class="fa-solid fa-star"></i></button>`:''}<button onclick="eliminarTicket('${t.id}')" class="text-instTomate hover:bg-red-50 p-2 rounded" title="Eliminar"><i class="fa-solid fa-trash"></i></button></td></tr>`}).join(''); }
    async function eliminarTicket(id){ if(!confirm('¿Eliminar este ticket?'))return; const {error}=await sbClient.from('tickets').delete().eq('id',id); if(error)return showToast(error.message,'error'); showToast('Ticket eliminado'); await loadTickets(); renderTickets(); }
    window.eliminarTicket=eliminarTicket;
    async function abrirModalLink(id){ const t=ticketsData.find(x=>x.id===id); if(!t)return; let token=t.rating_token; if(!token){ token=randomToken(); const {error}=await sbClient.from('tickets').update({rating_token:token}).eq('id',id); if(error)return showToast(error.message,'error'); t.rating_token=token; } const base=window.location.href.split('#')[0].split('?')[0]; const link=`${base}#rate_ticket=${encodeURIComponent(id)}&token=${encodeURIComponent(token)}`; $('url-valoracion').value=link; $('btn-test-valoracion').onclick=()=>{window.open(link,'_blank')}; $('modal-link-valoracion').classList.add('flex'); }
    window.abrirModalLink=abrirModalLink; window.cerrarModalLink=()=>$('modal-link-valoracion').classList.remove('flex'); window.copiarUrlValoracion=async()=>{const val=$('url-valoracion').value; try{await navigator.clipboard.writeText(val)}catch(e){$('url-valoracion').select();document.execCommand('copy')} showToast('Enlace copiado')};

    $('form-directorio').onsubmit=async e=>{e.preventDefault(); const u={cedula:$('dir-cedula').value,nombres:$('dir-nombres').value,correo:$('dir-correo').value,carrera:$('dir-carrera').value,nivel:$('dir-nivel').value,tipo:$('dir-tipo').value,periodo:$('dir-periodo').value}; const {error}=await sbClient.from('directorio').insert(u); if(error)return showToast(error.message,'error'); e.target.reset(); showToast('Usuario guardado'); await loadDirectory(); renderDirectorio(); };
    function renderDirectorio(){ $('dir-count').textContent=directorioData.length; $('empty-db-warning').classList.toggle('hidden',directorioData.length>0); $('directorio-table-body').innerHTML=directorioData.slice(0,100).map(u=>`<tr class="hover:bg-gray-50 border-b"><td class="px-4 py-3 font-medium">${esc(u.cedula)}</td><td class="px-4 py-3">${esc(u.nombres)}</td><td class="px-4 py-3 text-xs"><span class="bg-purple-100 text-purple-700 px-2 py-1 rounded">${esc(u.tipo)}</span></td><td class="px-4 py-3"><button onclick="eliminarUsuario('${u.id}')" class="text-red-500 hover:bg-red-50 p-1 rounded"><i class="fa-solid fa-trash"></i></button></td></tr>`).join('')+(directorioData.length>100?`<tr><td colspan="4" class="text-center py-4 text-xs text-gray-500 bg-gray-50">Mostrando 100 de ${directorioData.length}. Usa el buscador para encontrar usuarios.</td></tr>`:''); }
    async function eliminarUsuario(id){ if(!confirm('¿Eliminar usuario del directorio?'))return; const {error}=await sbClient.from('directorio').delete().eq('id',id); if(error)return showToast(error.message,'error'); showToast('Usuario eliminado'); await loadDirectory(); renderDirectorio(); }
    window.eliminarUsuario=eliminarUsuario;
    function renderAgents(){
      if($('agents-count')) $('agents-count').textContent = `${agentsData.length} agentes`;
      const admin = isAdmin();
      if($('agents-admin-panel')) $('agents-admin-panel').classList.toggle('hidden', !admin);
      if($('agents-not-admin')) $('agents-not-admin').classList.toggle('hidden', admin);
      $('agents-table-body').innerHTML=agentsData.map(a=>{
        const roleLabel=a.rol==='admin'?'Administrador':'Agente';
        const estado=a.activo?'<span class="bg-green-100 text-green-700 px-2 py-1 rounded text-xs">Activo</span>':'<span class="bg-red-100 text-red-700 px-2 py-1 rounded text-xs">Inactivo</span>';
        const actions=admin?`<div class="flex justify-center gap-1"><button onclick="editAgent('${a.id}')" class="text-blue-600 hover:bg-blue-50 p-2 rounded" title="Editar"><i class="fa-solid fa-pen"></i></button><button onclick="generateAgentLoginLink('${a.id}')" class="text-green-600 hover:bg-green-50 p-2 rounded" title="Generar URL"><i class="fa-solid fa-link"></i></button><button onclick="toggleAgentActive('${a.id}')" class="text-orange-600 hover:bg-orange-50 p-2 rounded" title="Activar/Inactivar"><i class="fa-solid fa-toggle-on"></i></button><button onclick="softDeleteAgent('${a.id}')" class="text-red-600 hover:bg-red-50 p-2 rounded" title="Eliminar lógico"><i class="fa-solid fa-trash"></i></button></div>`:'<span class="text-xs text-gray-400">Sin permisos</span>';
        return `<tr class="border-b hover:bg-gray-50"><td class="px-4 py-3 font-medium">${esc(a.nombre_completo)}</td><td class="px-4 py-3">${esc(a.email)}</td><td class="px-4 py-3"><span class="bg-indigo-100 text-indigo-700 px-2 py-1 rounded text-xs">${esc(roleLabel)}</span></td><td class="px-4 py-3">${estado}</td><td class="px-4 py-3 text-gray-500">${esc((a.created_at||'').slice(0,10))}</td><td class="px-4 py-3 text-center">${actions}</td></tr>`;
      }).join('');
    }
    function fillAgentAdminForm(agent){
      $('agent-edit-id').value = agent?.id || '';
      $('agent-admin-name').value = agent?.nombre_completo || '';
      $('agent-admin-email').value = agent?.email || '';
      $('agent-admin-role').value = agent?.rol === 'admin' ? 'admin' : 'agent';
      $('agent-admin-active').checked = agent?.activo !== false;
    }
    function clearAgentAdminForm(){ fillAgentAdminForm(null); $('agent-link-box').classList.add('hidden'); }
    function editAgent(id){ const agent=agentsData.find(a=>a.id===id); if(!agent)return; fillAgentAdminForm(agent); $('agent-admin-name').focus(); }
    async function updateAgentFromForm(e){
      e.preventDefault();
      if(!isAdmin()) return showToast('Solo administradores pueden modificar agentes','error');
      const id=$('agent-edit-id').value;
      if(!id) { generateAgentLoginLink(); return showToast('Para un agente nuevo, envía la URL directa. Cuando ingrese, podrás actualizar su perfil.','success'); }
      const payload={nombre_completo:$('agent-admin-name').value.trim()||$('agent-admin-email').value.trim(), email:$('agent-admin-email').value.trim(), rol:$('agent-admin-role').value, activo:$('agent-admin-active').checked};
      const {error}=await sbClient.from('agentes').update(payload).eq('id',id);
      if(error) return showToast(error.message,'error');
      showToast('Perfil de agente actualizado'); await loadAgents(); renderAgents();
    }
    async function toggleAgentActive(id){
      if(!isAdmin()) return showToast('Solo administradores pueden modificar agentes','error');
      const agent=agentsData.find(a=>a.id===id); if(!agent)return;
      if(agent.auth_user_id===currentUser?.id && agent.activo) return showToast('No puedes inactivar tu propio usuario activo','error');
      const {error}=await sbClient.from('agentes').update({activo:!agent.activo}).eq('id',id);
      if(error) return showToast(error.message,'error');
      showToast(agent.activo?'Agente inactivado':'Agente activado'); await loadAgents(); renderAgents();
    }
    async function softDeleteAgent(id){
      if(!isAdmin()) return showToast('Solo administradores pueden modificar agentes','error');
      const agent=agentsData.find(a=>a.id===id); if(!agent)return;
      if(agent.auth_user_id===currentUser?.id) return showToast('No puedes eliminar tu propio perfil','error');
      if(!confirm(`¿Eliminar/inactivar el agente ${agent.email}?`)) return;
      const {error}=await sbClient.from('agentes').update({activo:false, nombre_completo:`Eliminado - ${agent.nombre_completo||agent.email}`}).eq('id',id);
      if(error) return showToast(error.message,'error');
      showToast('Agente eliminado lógicamente'); clearAgentAdminForm(); await loadAgents(); renderAgents();
    }
    function buildAgentLoginUrl(agent){
      const email=agent?.email || $('agent-admin-email')?.value?.trim() || '';
      const name=agent?.nombre_completo || $('agent-admin-name')?.value?.trim() || '';
      const role=agent?.rol || $('agent-admin-role')?.value || 'agent';
      const params=new URLSearchParams({auth:'login'});
      if(email) params.set('email',email);
      if(name) params.set('name',name);
      if(role) params.set('role',role);
      return `${appBaseUrl()}?${params.toString()}`;
    }
    function generateAgentLoginLink(id){
      const agent=id?agentsData.find(a=>a.id===id):null;
      if(agent) fillAgentAdminForm(agent);
      if(!$('agent-admin-email').value.trim()) return showToast('Ingresa el correo del agente','error');
      $('agent-login-url').value=buildAgentLoginUrl(agent);
      $('agent-link-box').classList.remove('hidden');
      copyAgentLoginLink(false);
      showToast('URL directa generada');
    }
    async function copyAgentLoginLink(show=true){
      const url=$('agent-login-url').value;
      if(!url)return;
      try{await navigator.clipboard.writeText(url)}catch(e){$('agent-login-url').select();document.execCommand('copy')}
      if(show!==false) showToast('URL copiada');
    }
    window.editAgent=editAgent; window.toggleAgentActive=toggleAgentActive; window.softDeleteAgent=softDeleteAgent; window.clearAgentAdminForm=clearAgentAdminForm; window.generateAgentLoginLink=generateAgentLoginLink; window.copyAgentLoginLink=copyAgentLoginLink; if($('agent-admin-form')) $('agent-admin-form').onsubmit=updateAgentFromForm;


    function parseCSV(text){ const rows=[]; let row=[],cell='',q=false; for(let i=0;i<text.length;i++){const ch=text[i],nx=text[i+1]; if(ch==='"'&&q&&nx==='"'){cell+='"';i++;continue} if(ch==='"'){q=!q;continue} if(ch===','&&!q){row.push(cell);cell='';continue} if((ch==='\n'||ch==='\r')&&!q){ if(ch==='\r'&&nx==='\n')i++; row.push(cell); if(row.some(x=>x.trim()!==''))rows.push(row); row=[]; cell=''; continue } cell+=ch; } row.push(cell); if(row.some(x=>x.trim()!==''))rows.push(row); return rows; }
    function csvCell(v){ const s=String(v??''); return /[",\n\r]/.test(s)?'"'+s.replace(/"/g,'""')+'"':s; }
    function download(name,content,type){ const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([content],{type})); a.download=name; a.click(); URL.revokeObjectURL(a.href); }
    async function handleCSVUpload(event){ const f=event.target.files[0]; if(!f)return; $('file-name-display').textContent='Procesando...'; const rows=parseCSV(await f.text()); let count=0; const payload=[]; for(let i=1;i<rows.length;i++){const r=rows[i]; if(norm(r[0])) payload.push({cedula:norm(r[0]),nombres:norm(r[1])||'Sin Nombre',correo:norm(r[2]),carrera:norm(r[3]),nivel:norm(r[4]),tipo:norm(r[5])||'Estudiante',periodo:norm(r[6])}); } for(let i=0;i<payload.length;i+=500){const {error}=await sbClient.from('directorio').upsert(payload.slice(i,i+500),{onConflict:'cedula'}); if(error){showToast(error.message,'error');break} count+=payload.slice(i,i+500).length} $('file-name-display').textContent='Carga exitosa'; showToast(`Importados/actualizados ${count} usuarios`); await loadDirectory(); renderDirectorio(); event.target.value=''; }
    window.handleCSVUpload=handleCSVUpload;
    async function handleTicketsCSVUpload(event){ const f=event.target.files[0]; if(!f)return; const rows=parseCSV(await f.text()); if(rows.length<2){showToast('CSV vacío','error');return} const header=rows[0].map(h=>h.trim().toLowerCase()); const idx=n=>header.indexOf(n.toLowerCase()); const payload=[]; for(let i=1;i<rows.length;i++){const r=rows[i]; if(!r.length||!norm(r[idx('ID')]||r[0]))continue; const estado=norm(r[idx('Estado')])||'Requiere Seguimiento'; payload.push({id_str:norm(r[idx('ID')])||('TKT-'+String(Date.now()+i)),fecha_texto:norm(r[idx('Fecha')]),agente_nombre:norm(r[idx('Agente')])||currentProfile?.nombre_completo,usuario_cedula:norm(r[idx('Cedula_Usuario')]),usuario_nombre:norm(r[idx('Nombre_Usuario')]),asunto:norm(r[idx('Asunto')]),categoria:norm(r[idx('Categoria')]),subcategoria:norm(r[idx('Subcategoria')]),prioridad:norm(r[idx('Prioridad')])||'Media',canal:norm(r[idx('Canal')]),estado,valoracion_calificacion:Number(norm(r[idx('Valoracion_Estrellas')]))||null,valoracion_comentario:norm(r[idx('Comentario_Valoracion')]),rating_token:estado==='Resuelto'?randomToken():null}); }
      let count=0; for(let i=0;i<payload.length;i+=300){const {error}=await sbClient.from('tickets').upsert(payload.slice(i,i+300),{onConflict:'id_str'}); if(error){showToast(error.message,'error');break} count+=payload.slice(i,i+300).length} showToast(`Importados/actualizados ${count} tickets`); await loadTickets(); renderTickets(); populateDashboardFilters(); renderDashboard(); event.target.value=''; }
    window.handleTicketsCSVUpload=handleTicketsCSVUpload;
    function exportarCSV(){ if(!ticketsData.length)return showToast('No hay datos','error'); const header=['ID','Fecha','Agente','Cedula_Usuario','Nombre_Usuario','Asunto','Categoria','Subcategoria','Prioridad','Canal','Estado','Valoracion_Estrellas','Comentario_Valoracion']; const rows=ticketsData.map(t=>[t.id_str,t.fecha_texto||t.created_at,t.agente_nombre,t.usuario_cedula,t.usuario_nombre,t.asunto,t.categoria,t.subcategoria,t.prioridad,t.canal,t.estado,t.valoracion_calificacion||'',t.valoracion_comentario||'']); download('tickets.csv','\ufeff'+[header,...rows].map(r=>r.map(csvCell).join(',')).join('\n'),'text/csv;charset=utf-8'); }
    function exportarHTML(){ if(!ticketsData.length)return showToast('No hay datos','error'); const rows=ticketsData.map(t=>`<tr><td>${esc(t.id_str)}</td><td>${esc(t.fecha_texto||t.created_at)}</td><td>${esc(t.usuario_nombre)}</td><td>${esc(t.asunto)}</td><td>${esc(t.estado)}</td><td>${esc(t.valoracion_calificacion||'N/A')}</td><td>${esc(t.agente_nombre)}</td></tr>`).join(''); download('tickets.html',`<html><head><meta charset="UTF-8"><title>Tickets</title><style>table{width:100%;border-collapse:collapse;font-family:sans-serif}th,td{border:1px solid #ddd;padding:8px}th{background:#006068;color:white}</style></head><body><h2>Tickets</h2><table><tr><th>ID</th><th>Fecha</th><th>Usuario</th><th>Asunto</th><th>Estado</th><th>Valoración</th><th>Agente</th></tr>${rows}</table></body></html>`,'text/html'); }
    function exportarPDF(){ if(!ticketsData.length)return showToast('No hay datos','error'); $('pdf-table').innerHTML=`<thead><tr class="bg-gray-200"><th class="border p-2">ID</th><th class="border p-2">Fecha</th><th class="border p-2">Usuario</th><th class="border p-2">Asunto</th><th class="border p-2">Estrellas</th><th class="border p-2">Estado</th></tr></thead><tbody>`+ticketsData.map(t=>`<tr><td class="border p-2">${esc(t.id_str)}</td><td class="border p-2">${esc((t.created_at||'').slice(0,10))}</td><td class="border p-2">${esc(t.usuario_nombre)}</td><td class="border p-2">${esc(t.asunto)}</td><td class="border p-2 text-center">${esc(t.valoracion_calificacion||'-')}</td><td class="border p-2">${esc(t.estado)}</td></tr>`).join('')+'</tbody>'; const el=$('pdf-container');el.classList.remove('hidden');html2pdf().set({margin:10,filename:'tickets.pdf',jsPDF:{orientation:'landscape'}}).from(el).save().then(()=>el.classList.add('hidden')); }
    window.exportarCSV=exportarCSV; window.exportarHTML=exportarHTML; window.exportarPDF=exportarPDF;


    function informeFilters(){ return {from:$('inf-from')?.value||'',to:$('inf-to')?.value||'',estado:$('inf-estado')?.value||'',categoria:$('inf-categoria')?.value||'',agente:$('inf-agente')?.value||''}; }
    function filteredInformeData(){ const f=informeFilters(); return ticketsData.filter(t=>{const d=(t.created_at||'').slice(0,10); return (!f.from||d>=f.from)&&(!f.to||d<=f.to)&&(!f.estado||t.estado===f.estado)&&(!f.categoria||t.categoria===f.categoria)&&(!f.agente||t.agente_nombre===f.agente);}); }
    function calcInformeIndicators(data){ const total=data.length; const resueltos=data.filter(t=>t.estado==='Resuelto').length; const seguimiento=total-resueltos; const ratings=data.map(t=>Number(t.valoracion_calificacion)).filter(v=>v>0); const promedio=ratings.length?ratings.reduce((a,b)=>a+b,0)/ratings.length:0; const conValoracion=ratings.length; const resolucion=total?resueltos*100/total:0; const estados=counts(data,'estado'); const categorias=counts(data,'categoria'); const agentes=counts(data,'agente_nombre'); const prioridades=counts(data,'prioridad'); const canales=counts(data,'canal'); const diario={}; data.forEach(t=>{const d=(t.created_at||todayISO()).slice(0,10); diario[d]=(diario[d]||0)+1}); return {total,resueltos,seguimiento,promedio,conValoracion,resolucion,estados,categorias,agentes,prioridades,canales,diario}; }
    function tableHTML(obj,headers=['Indicador','Valor']){ const entries=Array.isArray(obj)?obj:Object.entries(obj); if(!entries.length)return '<p style="color:#666;font-size:12px">Sin datos para el periodo seleccionado.</p>'; return `<table class="doc-table"><thead><tr>${headers.map(h=>`<th>${esc(h)}</th>`).join('')}</tr></thead><tbody>${entries.map(r=>`<tr>${(Array.isArray(r)?r:[r[0],r[1]]).map(c=>`<td>${esc(c)}</td>`).join('')}</tr>`).join('')}</tbody></table>`; }
    function topEntries(obj,limit=10){ return Object.entries(obj).sort((a,b)=>b[1]-a[1]).slice(0,limit); }
    function populateInformeFilters(){ if(!$('inf-categoria'))return; const catSel=$('inf-categoria'), agSel=$('inf-agente'); const cv=catSel.value,av=agSel.value; catSel.innerHTML='<option value="">Todas las categorías</option>'+[...new Set(ticketsData.map(t=>t.categoria).filter(Boolean))].map(c=>`<option>${esc(c)}</option>`).join(''); agSel.innerHTML='<option value="">Todos los agentes</option>'+[...new Set(ticketsData.map(t=>t.agente_nombre).filter(Boolean))].map(a=>`<option>${esc(a)}</option>`).join(''); catSel.value=cv; agSel.value=av; if(!$('inf-author').value) $('inf-author').value=currentProfile?.nombre_completo||currentUser?.email||''; }
    function renderInformePreview(){ if(!$('informe-preview'))return; const data=filteredInformeData(); const ind=calcInformeIndicators(data); $('inf-count').textContent=`${ind.total} tickets`; const kpis=[['Total tickets',ind.total],['Resueltos',ind.resueltos],['Seguimiento',ind.seguimiento],['Resolución',ind.resolucion.toFixed(0)+'%'],['Valoración promedio',ind.promedio.toFixed(1)],['Tickets valorados',ind.conValoracion]]; $('informe-preview').innerHTML=`<div class="grid grid-cols-2 md:grid-cols-3 gap-3">${kpis.map(k=>`<div class="border rounded-xl p-4 bg-gray-50"><p class="text-xs text-instPlomo uppercase font-semibold">${esc(k[0])}</p><p class="text-2xl font-bold text-instVerdeOscuro">${esc(k[1])}</p></div>`).join('')}</div><div class="grid grid-cols-1 md:grid-cols-2 gap-4"><div><h4 class="font-semibold text-instVerdeOscuro mb-2">Categorías principales</h4>${tableHTML(topEntries(ind.categorias,8))}</div><div><h4 class="font-semibold text-instVerdeOscuro mb-2">Agentes</h4>${tableHTML(topEntries(ind.agentes,8))}</div></div>`; }
    ['inf-from','inf-to','inf-estado','inf-categoria','inf-agente','inf-anexos','inf-title','inf-author'].forEach(id=>document.addEventListener('change',e=>{if(e.target&&e.target.id===id)renderInformePreview()}));
    function ticketUserType(t){ const byId=directorioData.find(u=>u.id&&t.usuario_id&&u.id===t.usuario_id); const byCedula=directorioData.find(u=>u.cedula&&t.usuario_cedula&&String(u.cedula)===String(t.usuario_cedula)); const byName=directorioData.find(u=>(u.nombres||'').toLowerCase()===(t.usuario_nombre||'').toLowerCase()); return t.usuario_tipo||t.tipo_usuario||(byId||byCedula||byName)?.tipo||'No especificado'; }
    function informeTicketRows(data){ return data.map((t,i)=>`<tr><td>${i+1}</td><td>${esc(t.id_str)}</td><td>${esc((t.created_at||'').slice(0,10))}</td><td>${esc(ticketUserType(t))}</td><td>${esc(t.usuario_nombre)}</td><td>${esc(t.asunto)}</td><td>${esc(t.categoria)}</td><td>${esc(t.prioridad)}</td><td>${esc(t.estado)}</td><td>${esc(t.valoracion_calificacion||'-')}</td><td>${esc(t.agente_nombre)}</td></tr>`).join(''); }
    function buildInformeHTML(){ const data=filteredInformeData(); const ind=calcInformeIndicators(data); const f=informeFilters(); const title=$('inf-title')?.value||'Informe documental de indicadores de gestión de incidentes'; const author=$('inf-author')?.value||currentProfile?.nombre_completo||currentUser?.email||'Agente'; const mes=new Date().toLocaleDateString('es-EC',{month:'long',year:'numeric'}).toUpperCase(); const periodo=[f.from||'inicio',f.to||'actual'].join(' - '); const kpis=[['Total de tickets',ind.total],['Tickets resueltos',ind.resueltos],['Tickets en seguimiento',ind.seguimiento],['Porcentaje de resolución',ind.resolucion.toFixed(1)+'%'],['Promedio de valoración',ind.promedio.toFixed(1)+' / 5'],['Tickets con valoración',ind.conValoracion]]; const anexos=$('inf-anexos')?.checked; const logoCordillera='data:image/png;base64,'; const ccLogo='data:image/png;base64,'; return `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>@page{size:A4;margin:2.7cm 2.3cm 2.5cm 2.3cm}body{font-family:Arial,Helvetica,sans-serif;color:#222;line-height:1.55;font-size:12pt}p,li{font-size:12pt}h1,h2,h3{font-family:Arial,Helvetica,sans-serif;color:#006068;margin-top:18px;margin-bottom:10px;page-break-after:avoid}h1{text-align:center;font-size:24pt;font-weight:700;margin-top:32px;line-height:1.25}h2{font-size:18pt;font-weight:700;text-transform:uppercase;border-bottom:2px solid #00CE7C;padding-bottom:6px}h3{font-size:14pt;font-weight:700}.cover{min-height:850px;text-align:center;position:relative;padding-top:40px}.cover-logo{width:330px;max-width:80%;margin:0 auto 55px auto;display:block}.brand{height:14px;background:#00CE7C;margin:28px 0;border-radius:8px}.subtitle{color:#666;font-size:14pt;letter-spacing:.3px}.doc-meta{margin-top:42px;color:#333}.license{font-size:10pt;color:#666;margin-top:60px}.license img{height:28px;vertical-align:middle;margin-right:8px}.section-head{display:flex;align-items:center;gap:18px;border-bottom:4px solid #00CE7C;padding-bottom:12px;margin-bottom:22px}.section-head img{height:52px;width:auto}.section-head .small{font-size:10pt;color:#666;margin:0}.doc-table{border-collapse:collapse;width:100%;margin:12px 0 22px 0;font-size:10pt;page-break-inside:auto}.doc-table th{background:#006068;color:white;border:1px solid #006068;padding:7px;text-align:left;font-weight:700}.doc-table td{border:1px solid #ccc;padding:6px;vertical-align:top}.anexo-table{font-size:8.5pt;line-height:1.25;table-layout:fixed}.anexo-table th,.anexo-table td{padding:5px;word-break:break-word}.anexo-table th:nth-child(1),.anexo-table td:nth-child(1){width:4%}.anexo-table th:nth-child(2),.anexo-table td:nth-child(2){width:9%}.anexo-table th:nth-child(3),.anexo-table td:nth-child(3){width:8%}.anexo-table th:nth-child(4),.anexo-table td:nth-child(4){width:10%}.anexo-table th:nth-child(5),.anexo-table td:nth-child(5){width:15%}.anexo-table th:nth-child(6),.anexo-table td:nth-child(6){width:16%}.anexo-table th:nth-child(7),.anexo-table td:nth-child(7){width:12%}.callout{border-left:6px solid #E47E3D;background:#fff7ed;padding:12px;margin:18px 0}.kpi-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:16px 0 20px}.kpi{border:1px solid #ddd;border-top:5px solid #00CE7C;padding:12px;background:#fff}.kpi span{color:#666;font-size:10pt;text-transform:uppercase;font-weight:700}.kpi b{display:block;color:#006068;font-size:18pt;margin-top:6px}.footer{text-align:center;color:#666;font-size:10pt;margin-top:40px;border-top:1px solid #ddd;padding-top:10px}.page-break{page-break-before:always}.avoid-break{page-break-inside:avoid}</style></head><body><div class="cover"><img class="cover-logo" src="${logoCordillera}" alt="Instituto Superior Tecnológico Cordillera"><p class="subtitle">Plantilla Documental Cordillera</p><h1>${esc(title)}</h1><div class="brand"></div><p class="subtitle">${esc(mes)}</p><div class="doc-meta"><p><strong>${esc(author)}</strong></p><p>Quito - Ecuador</p></div><p class="license"><img src="${ccLogo}" alt="Licencia Creative Commons"> Esta obra se presenta como evidencia documental interna de gestión de incidentes y atención de soporte.</p></div><div class="page-break"></div><div class="section-head"><img src="${logoCordillera}" alt="Instituto Superior Tecnológico Cordillera"><div><p class="small">Informe documental</p><h2>CONTENIDO</h2></div></div><ol><li>Introducción o resumen</li><li>Alcance y filtros aplicados</li><li>Indicadores principales</li><li>Análisis por estado, categoría, prioridad, canal y agente</li><li>Evidencia de registros</li><li>Recomendaciones</li><li>Anexos</li></ol><h2>INTRODUCCIÓN O RESUMEN</h2><p>El presente informe consolida los indicadores operativos del módulo de registros de incidentes. El objetivo es presentar evidencia concreta sobre volumen de atención, resolución, seguimiento, categorías recurrentes, canales de ingreso, participación de agentes y nivel de satisfacción reportado por los usuarios.</p><div class="callout"><strong>Nota importante:</strong> Los resultados se generan automáticamente con base en los tickets registrados en el sistema al momento de emitir el documento.</div><h2>ALCANCE Y FILTROS APLICADOS</h2>${tableHTML([['Periodo',periodo],['Estado',f.estado||'Todos'],['Categoría',f.categoria||'Todas'],['Agente',f.agente||'Todos'],['Fecha de generación',new Date().toLocaleString()]],['Campo','Valor'])}<h2>INDICADORES PRINCIPALES</h2><div class="kpi-grid">${kpis.map(k=>`<div class="kpi"><span>${esc(k[0])}</span><b>${esc(k[1])}</b></div>`).join('')}</div><h2>ANÁLISIS POR DIMENSIÓN</h2><h3>Tickets por estado</h3>${tableHTML(topEntries(ind.estados,20))}<h3>Tickets por categoría</h3>${tableHTML(topEntries(ind.categorias,20))}<h3>Tickets por prioridad</h3>${tableHTML(topEntries(ind.prioridades,20))}<h3>Tickets por canal de ingreso</h3>${tableHTML(topEntries(ind.canales,20))}<h3>Tickets por agente</h3>${tableHTML(topEntries(ind.agentes,20))}<h3>Tendencia diaria</h3>${tableHTML(Object.entries(ind.diario).sort(),['Fecha','Tickets'])}<h2>RECOMENDACIONES</h2><ul><li>Priorizar las categorías con mayor recurrencia para reducir incidentes repetitivos.</li><li>Revisar tickets en seguimiento y definir tiempos máximos de cierre.</li><li>Fortalecer el proceso de solicitud de valoración para incrementar evidencia de satisfacción.</li><li>Usar este informe como respaldo documental en reuniones de seguimiento y mejora continua.</li></ul>${anexos?`<div class="page-break"></div><div class="section-head"><img src="${logoCordillera}" alt="Instituto Superior Tecnológico Cordillera"><div><p class="small">Evidencia documental</p><h2>ANEXOS</h2></div></div><h3>Anexo 1. Detalle de tickets incluidos</h3><table class="doc-table anexo-table"><thead><tr><th>#</th><th>ID</th><th>Fecha</th><th>Tipo</th><th>Usuario</th><th>Asunto</th><th>Categoría</th><th>Prioridad</th><th>Estado</th><th>Valoración</th><th>Agente</th></tr></thead><tbody>${informeTicketRows(data)}</tbody></table>`:''}<div class="footer">www.cordillera.edu.ec - Instituto Tecnológico Superior Cordillera</div></body></html>`; }
    async function registrarInforme(formato,ind){ try{ await sbClient.from('informes_documentales').insert({titulo:$('inf-title')?.value||'Informe documental',generado_por:currentProfile?.id||null,generado_por_nombre:currentProfile?.nombre_completo||currentUser?.email||'',filtros:informeFilters(),indicadores:ind,total_tickets:ind.total,formato}); }catch(e){ console.warn('No se pudo registrar metadatos del informe',e); } }
    async function exportarInformeDocumental(formato){ const data=filteredInformeData(); if(!data.length)return showToast('No hay datos para el informe','error'); const ind=calcInformeIndicators(data); const html=buildInformeHTML(); const fname='informe_documental_incidentes_'+todayISO(); if(formato==='html'){download(fname+'.html',html,'text/html;charset=utf-8'); await registrarInforme('html',ind); return showToast('Informe HTML generado');} if(formato==='pdf'){const cont=$('informe-doc-container'); cont.innerHTML=html; cont.classList.remove('hidden'); await html2pdf().set({margin:10,filename:fname+'.pdf',html2canvas:{scale:2},jsPDF:{orientation:'portrait',unit:'mm',format:'a4'}}).from(cont).save(); cont.classList.add('hidden'); await registrarInforme('pdf',ind); return showToast('Informe PDF generado');} if(formato==='docx'){ if(window.htmlDocx&&window.htmlDocx.asBlob){ const blob=window.htmlDocx.asBlob(html); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=fname+'.docx'; a.click(); URL.revokeObjectURL(a.href); await registrarInforme('docx',ind); return showToast('Informe DOCX generado'); } download(fname+'.doc',html,'application/msword'); await registrarInforme('doc',ind); return showToast('No cargó el generador DOCX; se descargó Word HTML'); } }
    window.renderInformePreview=renderInformePreview; window.exportarInformeDocumental=exportarInformeDocumental;

    function actualizarSelectsConfig(){ const cats=configData.categorias||[], cans=configData.canales||[]; $('t-categoria').innerHTML=cats.map(c=>`<option value="${esc(c)}">${esc(c)}</option>`).join(''); $('t-canal').innerHTML=cans.map(c=>`<option value="${esc(c)}">${esc(c)}</option>`).join(''); $('list-categorias').innerHTML=cats.map((c,i)=>`<span class="bg-gray-100 text-sm px-3 py-1 rounded-full flex items-center gap-2 border">${esc(c)} <i onclick="removeConfigItem('categorias',${i})" class="fa-solid fa-xmark text-red-500 cursor-pointer"></i></span>`).join(''); $('list-canales').innerHTML=cans.map((c,i)=>`<span class="bg-gray-100 text-sm px-3 py-1 rounded-full flex items-center gap-2 border">${esc(c)} <i onclick="removeConfigItem('canales',${i})" class="fa-solid fa-xmark text-red-500 cursor-pointer"></i></span>`).join(''); }
    async function saveConfig(){ const {error}=await sbClient.from('app_config').upsert({id:1,config:configData,updated_by:currentProfile?.id||null}); if(error)showToast(error.message,'error'); }
    async function addConfigItem(t,id){ const val=$(id).value.trim(); if(!val)return; configData[t]=configData[t]||[]; if(!configData[t].includes(val))configData[t].push(val); await saveConfig(); $(id).value=''; actualizarSelectsConfig(); populateDashboardFilters(); }
    async function removeConfigItem(t,i){ configData[t].splice(i,1); await saveConfig(); actualizarSelectsConfig(); populateDashboardFilters(); }
    window.addConfigItem=addConfigItem; window.removeConfigItem=removeConfigItem;

    ['dash-from','dash-to','dash-estado','dash-categoria','dash-agente'].forEach(id=>document.addEventListener('change',e=>{if(e.target&&e.target.id===id)renderDashboard()}));
    function populateDashboardFilters(){ const catSel=$('dash-categoria'), agSel=$('dash-agente'); const cv=catSel.value,av=agSel.value; catSel.innerHTML='<option value="">Todas las categorías</option>'+[...new Set(ticketsData.map(t=>t.categoria).filter(Boolean))].map(c=>`<option>${esc(c)}</option>`).join(''); agSel.innerHTML='<option value="">Todos los agentes</option>'+[...new Set(ticketsData.map(t=>t.agente_nombre).filter(Boolean))].map(a=>`<option>${esc(a)}</option>`).join(''); catSel.value=cv; agSel.value=av; }
    function resetDashboardFilters(){ ['dash-from','dash-to','dash-estado','dash-categoria','dash-agente'].forEach(id=>$(id).value=''); renderDashboard(); }
    window.resetDashboardFilters=resetDashboardFilters;
    function filteredDashboardData(){ const from=$('dash-from').value,to=$('dash-to').value,estado=$('dash-estado').value,cat=$('dash-categoria').value,ag=$('dash-agente').value; return ticketsData.filter(t=>{const d=(t.created_at||'').slice(0,10); return (!from||d>=from)&&(!to||d<=to)&&(!estado||t.estado===estado)&&(!cat||t.categoria===cat)&&(!ag||t.agente_nombre===ag);}); }
    function counts(arr,key){ return arr.reduce((o,t)=>{const k=t[key]||'Sin dato';o[k]=(o[k]||0)+1;return o},{}) }
    function renderChart(id,type,labels,data,label){
      const canvas=$(id);
      if(!canvas) return;
      if(typeof Chart==='undefined') { console.warn('Chart.js no cargó; se omite gráfico', id); return; }
      if(charts[id])charts[id].destroy();
      charts[id]=new Chart(canvas,{type,data:{labels,datasets:[{label,data,borderWidth:2,borderRadius:5,tension:.3}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',display:type!=='bar'||id==='chartAgent'}},scales:type==='doughnut'||type==='pie'?{}:{y:{beginAtZero:true,ticks:{precision:0}}}}});
    }
    function renderDashboard(){ const data=filteredDashboardData(); const total=data.length,res=data.filter(t=>t.estado==='Resuelto').length,seg=total-res; const ratings=data.map(t=>t.valoracion_calificacion).filter(Boolean); $('kpi-total').textContent=total; $('kpi-resueltos').textContent=res; $('kpi-seguimiento').textContent=seg; $('kpi-rating').textContent=ratings.length?(ratings.reduce((a,b)=>a+b,0)/ratings.length).toFixed(1):'0.0'; $('kpi-resolution').textContent=total?Math.round(res*100/total)+'%':'0%'; const st=counts(data,'estado'),ct=counts(data,'categoria'),ag=counts(data,'agente_nombre'); const daily={}; data.forEach(t=>{const d=(t.created_at||todayISO()).slice(0,10);daily[d]=(daily[d]||0)+1}); const days=Object.keys(daily).sort(); renderChart('chartStatus','doughnut',Object.keys(st),Object.values(st),'Tickets'); renderChart('chartCategory','bar',Object.keys(ct),Object.values(ct),'Tickets'); renderChart('chartLine','line',days,days.map(d=>daily[d]),'Tickets por día'); renderChart('chartAgent','bar',Object.keys(ag),Object.values(ag),'Tickets por agente'); }

    sbClient.auth.onAuthStateChange(async (event,session)=>{ if(event==='PASSWORD_RECOVERY'){showToast('Ingresa tu nueva contraseña desde el panel de Supabase Auth. Esta versión estática ya recibió la sesión.')} });
    initApp();
  